import { DEFAULT_SETTINGS, STORAGE_KEY } from "./constants";
import type { ExtensionState } from "./types";

function normalizeLanguage(value: unknown): ExtensionState["settings"]["language"] {
  return value === "en" || value === "zh" ? value : DEFAULT_SETTINGS.language;
}

function normalizeSettings(settings: Partial<ExtensionState["settings"]> | undefined): ExtensionState["settings"] {
  return {
    ...DEFAULT_SETTINGS,
    language: normalizeLanguage(settings?.language)
  };
}

export function defaultState(): ExtensionState {
  return {
    claudePage: {
      isOpen: false,
      limitStatus: "unknown"
    },
    tasks: [],
    settings: { ...DEFAULT_SETTINGS },
    updatedAt: Date.now()
  };
}

export async function loadState(): Promise<ExtensionState> {
  const stored = await chrome.storage.local.get(STORAGE_KEY);
  const existing = stored[STORAGE_KEY] as Partial<ExtensionState> | undefined;
  const fallback = defaultState();
  return {
    ...fallback,
    ...existing,
    claudePage: {
      ...fallback.claudePage,
      ...existing?.claudePage
    },
    settings: normalizeSettings(existing?.settings),
    tasks: Array.isArray(existing?.tasks) ? existing.tasks : []
  };
}

export async function saveState(state: ExtensionState): Promise<ExtensionState> {
  const next = {
    ...state,
    settings: normalizeSettings(state.settings),
    updatedAt: Date.now()
  };
  await chrome.storage.local.set({ [STORAGE_KEY]: next });
  return next;
}

export async function updateState(mutator: (state: ExtensionState) => ExtensionState | Promise<ExtensionState>): Promise<ExtensionState> {
  const current = await loadState();
  const next = await mutator(current);
  return saveState(next);
}
